import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';

export default function Navbar() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  return (
    <nav className="bg-blue-700 text-white shadow-md" aria-label="Navegación principal">
      <div className="container mx-auto px-4">
        <div className="flex justify-between items-center py-3 flex-wrap">
          <div className="text-xl font-bold">Sistema de Gestión</div>
          <div className="flex space-x-4 items-center flex-wrap">
            <Link to="/" className="hover:bg-blue-800 px-3 py-2 rounded">Dashboard</Link>
            <Link to="/productos" className="hover:bg-blue-800 px-3 py-2 rounded">Productos</Link>
            <Link to="/compras" className="hover:bg-blue-800 px-3 py-2 rounded">Compras</Link>
            <Link to="/ventas" className="hover:bg-blue-800 px-3 py-2 rounded">Ventas</Link>
            {user?.rol === 'admin' && (
              <>
                <Link to="/usuarios" className="hover:bg-blue-800 px-3 py-2 rounded">Usuarios</Link>
                <Link to="/proveedores" className="hover:bg-blue-800 px-3 py-2 rounded">Proveedores</Link>
              </>
            )}
            <span className="text-sm">Hola, {user?.nombre} ({user?.rol})</span>
            <button onClick={handleLogout} className="bg-red-600 px-3 py-1 rounded text-sm">Salir</button>
          </div>
        </div>
      </div>
    </nav>
  );
}
